package cmd

import (
	"encoding/json"
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/spf13/cobra"
)

type cleanupCommandReport struct {
	DryRun                      bool                                `json:"dry_run"`
	ProjectRoot                 string                              `json:"project_root"`
	TempRoot                    string                              `json:"temp_root"`
	ScannedTempDirs             int                                 `json:"scanned_temp_dirs"`
	ScannedEvidenceDirs         int                                 `json:"scanned_evidence_dirs"`
	CompleteEvidenceDirs        int                                 `json:"complete_evidence_dirs"`
	ScannedScratchDirs          int                                 `json:"scanned_scratch_dirs"`
	RemovedUnregisteredTempDirs int64                               `json:"removed_unregistered_temp_dirs"`
	RemovedRegisteredWorktrees  int64                               `json:"removed_registered_worktrees"`
	RemovedRunStateFiles        int64                               `json:"removed_run_state_files"`
	RemovedScratchDirs          int64                               `json:"removed_scratch_dirs"`
	PreservedActiveScratchDirs  int64                               `json:"preserved_active_scratch_dirs"`
	BytesReclaimed              int64                               `json:"bytes_reclaimed"`
	InodesReclaimed             int64                               `json:"inodes_reclaimed"`
	ScratchBytesReclaimed       int64                               `json:"scratch_bytes_reclaimed"`
	ScratchInodesReclaimed      int64                               `json:"scratch_inodes_reclaimed"`
	Warnings                    []agent.ExecutionCleanupWarning     `json:"warnings"`
	BlockedErrors               []agent.ExecutionCleanupIssue       `json:"blocked_errors"`
	Observations                []agent.ExecutionCleanupObservation `json:"observations"`
}

func (f *CommandFactory) newCleanupCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "cleanup",
		Short: "Inspect and clean stale DDx execution resources",
		Long: `Inspect DDx-owned execution resources and conservatively clean stale state.

By default, cleanup runs in dry-run mode and reports what it would remove.
Use --apply to remove stale DDx temp worktrees, stale run-state files, and
other DDx-owned scratch resources under the configured project roots.

Examples:
  ddx cleanup
  ddx cleanup --json
  ddx cleanup --apply
  ddx cleanup --project /path/to/project --apply`,
		Args: cobra.NoArgs,
		RunE: f.runCleanup,
	}

	cmd.Flags().Bool("apply", false, "Actually remove stale DDx execution resources")
	cmd.Flags().Bool("json", false, "Output the cleanup report as JSON")
	cmd.Flags().String("project", "", "Project root to inspect (default: detected from CWD)")
	return cmd
}

func (f *CommandFactory) runCleanup(cmd *cobra.Command, args []string) error {
	_ = args
	projectFlag, _ := cmd.Flags().GetString("project")
	apply, _ := cmd.Flags().GetBool("apply")
	asJSON, _ := cmd.Flags().GetBool("json")

	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
	if projectRoot == "" {
		projectRoot = f.WorkingDir
	}

	mgr := agent.NewExecutionCleanupManager(projectRoot, &agent.RealGitOps{})
	mgr.DryRun = !apply

	summary, err := mgr.Cleanup(cmd.Context())
	if err != nil {
		return err
	}

	report := cleanupCommandReport{
		DryRun:                      !apply,
		ProjectRoot:                 summary.ProjectRoot,
		TempRoot:                    summary.TempRoot,
		ScannedTempDirs:             summary.ScannedTempDirs,
		ScannedEvidenceDirs:         summary.ScannedEvidenceDirs,
		CompleteEvidenceDirs:        summary.CompleteEvidenceDirs,
		ScannedScratchDirs:          summary.ScannedScratchDirs,
		RemovedUnregisteredTempDirs: summary.RemovedUnregisteredTempDirs,
		RemovedRegisteredWorktrees:  summary.RemovedRegisteredWorktrees,
		RemovedRunStateFiles:        summary.RemovedRunStateFiles,
		RemovedScratchDirs:          summary.RemovedScratchDirs,
		PreservedActiveScratchDirs:  summary.PreservedActiveScratchDirs,
		BytesReclaimed:              summary.BytesReclaimed,
		InodesReclaimed:             summary.InodesReclaimed,
		ScratchBytesReclaimed:       summary.ScratchBytesReclaimed,
		ScratchInodesReclaimed:      summary.ScratchInodesReclaimed,
		Warnings:                    append([]agent.ExecutionCleanupWarning(nil), summary.Warnings...),
		Observations:                append([]agent.ExecutionCleanupObservation(nil), summary.Observations...),
	}
	for _, issue := range summary.Issues {
		if issue.Blocking {
			report.BlockedErrors = append(report.BlockedErrors, issue)
		}
	}
	if report.Warnings == nil {
		report.Warnings = []agent.ExecutionCleanupWarning{}
	}
	if report.BlockedErrors == nil {
		report.BlockedErrors = []agent.ExecutionCleanupIssue{}
	}
	if report.Observations == nil {
		report.Observations = []agent.ExecutionCleanupObservation{}
	}

	if asJSON {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(report)
	}

	out := cmd.OutOrStdout()
	verb := "removed"
	if report.DryRun {
		verb = "would remove"
	}
	fmt.Fprintf(out, "cleanup: %s %d stale temp dir(s), %d registered worktree(s), %d run-state file(s), %d scratch dir(s)\n",
		verb,
		report.RemovedUnregisteredTempDirs,
		report.RemovedRegisteredWorktrees,
		report.RemovedRunStateFiles,
		report.RemovedScratchDirs,
	)
	if report.BytesReclaimed > 0 || report.InodesReclaimed > 0 {
		fmt.Fprintf(out, "cleanup: %s %d byte(s), %d inode(s)\n", verb, report.BytesReclaimed, report.InodesReclaimed)
	}
	if report.ScratchBytesReclaimed > 0 || report.ScratchInodesReclaimed > 0 || report.PreservedActiveScratchDirs > 0 {
		fmt.Fprintf(out, "cleanup: scratch scope %s %d byte(s), %d inode(s); preserved %d active scratch dir(s)\n",
			verb,
			report.ScratchBytesReclaimed,
			report.ScratchInodesReclaimed,
			report.PreservedActiveScratchDirs,
		)
	}
	if report.CompleteEvidenceDirs > 0 {
		fmt.Fprintf(out, "cleanup: preserved %d complete evidence bundle(s)\n", report.CompleteEvidenceDirs)
	}
	for _, warning := range report.Warnings {
		fmt.Fprintf(out, "warning: %s (%s): %s\n", warning.Path, warning.Class, warning.Message)
	}
	for _, issue := range report.BlockedErrors {
		fmt.Fprintf(out, "blocked: %s (%s): %s\n", issue.Path, issue.Class, issue.Message)
	}
	if report.DryRun {
		fmt.Fprintln(out, "run again with --apply to remove these resources")
	}
	return nil
}

package agent

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

// ExecutionCleanupMetadataFileName is the filename used to describe ownership
// and liveness for a DDx temp execution directory.
const ExecutionCleanupMetadataFileName = "cleanup.json"

const defaultExecutionCleanupScratchMinAge = 6 * time.Hour
const defaultEvidenceRetainDays = 90

var defaultExecutionCleanupScratchPrefixes = []string{
	"ddx-test-",
	"ddx-e2e-",
	"ddx-test-bin-",
	"ddx-test-binary-",
	"ddx-lifecycle-",
	"ddx-agent-support-keepalive",
	"ddx-config-anchor-",
	"ddx-exec-keepalive",
	"ddx-metric-keepalive",
	"ddx-metaprompt-keepalive",
	"ddx-persona-keepalive",
	"ddx-vale-",
	"ddx-gate-wt-",
	"ddx-land-finalize-",
	"ddx-land-wt-",
	"ddx-push-recover-",
	"ddx-conflict-recover-",
}

// ExecutionCleanupLiveness records the refreshable liveness signal attached to
// a temp execution directory.
type ExecutionCleanupLiveness struct {
	PID          int       `json:"pid,omitempty"`
	SessionID    string    `json:"session_id,omitempty"`
	RefreshedAt  time.Time `json:"refreshed_at,omitempty"`
	ExpiresAt    time.Time `json:"expires_at,omitempty"`
	LastChecked  time.Time `json:"last_checked,omitempty"`
	HeartbeatSeq int       `json:"heartbeat_seq,omitempty"`
}

// ExecutionCleanupMetadata records the ownership metadata for one DDx temp
// execution directory.
type ExecutionCleanupMetadata struct {
	ProjectRoot  string `json:"project_root,omitempty"`
	BeadID       string `json:"bead_id,omitempty"`
	AttemptID    string `json:"attempt_id,omitempty"`
	WorktreePath string `json:"worktree_path,omitempty"`
	Registered   bool   `json:"registered,omitempty"`
	Preserved    bool   `json:"preserved,omitempty"`
	// ActiveCandidateCycle is set by AttemptCycleCoordinator while it holds the
	// worktree open for candidate evaluation (checks, review, repair). The
	// cleanup manager preserves any worktree with this flag set so it is never
	// deleted mid-cycle before the coordinator reaches terminal disposition.
	ActiveCandidateCycle bool `json:"active_candidate_cycle,omitempty"`
	// Candidate-cycle metadata lets crash recovery distinguish a stale
	// unpinned worktree from one that still has a project-root candidate ref
	// worth preserving for operator inspection.
	CandidateCyclePhase string                    `json:"candidate_cycle_phase,omitempty"`
	CandidateRef        string                    `json:"candidate_ref,omitempty"`
	CandidateRev        string                    `json:"candidate_rev,omitempty"`
	CycleIndex          int                       `json:"cycle_index,omitempty"`
	ReviewActive        bool                      `json:"review_active,omitempty"`
	RepairActive        bool                      `json:"repair_active,omitempty"`
	CreatedAt           time.Time                 `json:"created_at,omitempty"`
	Liveness            *ExecutionCleanupLiveness `json:"liveness,omitempty"`
}

// ExecutionCleanupObservation is a structured note emitted by the cleanup
// manager when it preserves or removes a resource.
type ExecutionCleanupObservation struct {
	Path    string `json:"path"`
	Class   string `json:"class"`
	Message string `json:"message"`
	Bytes   int64  `json:"bytes,omitempty"`
	Inodes  int64  `json:"inodes,omitempty"`
}

// ExecutionCleanupWarning records a non-blocking issue encountered while the
// manager was scanning or reclaiming execution resources.
type ExecutionCleanupWarning struct {
	Path    string `json:"path,omitempty"`
	Class   string `json:"class"`
	Message string `json:"message"`
}

// ExecutionCleanupIssue records a blocking failure for a path the cleanup
// manager tried to reclaim.
type ExecutionCleanupIssue struct {
	Path     string `json:"path"`
	Class    string `json:"class"`
	Message  string `json:"message"`
	Blocking bool   `json:"blocking"`
}

// ExecutionCleanupSummary is the structured result of one cleanup pass.
type ExecutionCleanupSummary struct {
	ProjectRoot string `json:"project_root"`
	TempRoot    string `json:"temp_root"`

	ScannedTempDirs      int `json:"scanned_temp_dirs"`
	ScannedEvidenceDirs  int `json:"scanned_evidence_dirs"`
	CompleteEvidenceDirs int `json:"complete_evidence_dirs"`
	ScannedScratchDirs   int `json:"scanned_scratch_dirs"`

	RemovedUnregisteredTempDirs int64 `json:"removed_unregistered_temp_dirs"`
	RemovedRegisteredWorktrees  int64 `json:"removed_registered_worktrees"`
	RemovedRunStateFiles        int64 `json:"removed_run_state_files"`
	RemovedScratchDirs          int64 `json:"removed_scratch_dirs"`
	PreservedActiveScratchDirs  int64 `json:"preserved_active_scratch_dirs"`
	PrunedCandidateRefs         int64 `json:"pruned_candidate_refs"`
	RemovedEvidenceDirs         int64 `json:"removed_evidence_dirs"`
	RemovedAgentLogs            int64 `json:"removed_agent_logs"`
	RemovedWorkerDirs           int64 `json:"removed_worker_dirs"`

	BytesReclaimed         int64 `json:"bytes_reclaimed"`
	InodesReclaimed        int64 `json:"inodes_reclaimed"`
	ScratchBytesReclaimed  int64 `json:"scratch_bytes_reclaimed"`
	ScratchInodesReclaimed int64 `json:"scratch_inodes_reclaimed"`

	Warnings     []ExecutionCleanupWarning     `json:"warnings,omitempty"`
	Issues       []ExecutionCleanupIssue       `json:"issues,omitempty"`
	Observations []ExecutionCleanupObservation `json:"observations,omitempty"`
}

// ExecutionCleanupLivenessProbe decides whether a cleanup candidate should be
// preserved because it is still live.
type ExecutionCleanupLivenessProbe interface {
	IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string)
}

// defaultExecutionCleanupLivenessProbe preserves preserved metadata, a temp
// execution directory referenced by the live run-state file, or a candidate
// with an unexpired liveness marker. Tests can override the probe to model
// more specific host behavior.
type defaultExecutionCleanupLivenessProbe struct{}

func (defaultExecutionCleanupLivenessProbe) IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string) {
	if meta.Preserved {
		return true, "preserved metadata"
	}
	if meta.ActiveCandidateCycle {
		return true, candidateCycleRecoveryReason(meta, "active candidate cycle")
	}
	if strings.TrimSpace(meta.CandidateRef) != "" {
		return true, candidateCycleRecoveryReason(meta, "candidate ref recovery")
	}
	if runState != nil {
		if strings.TrimSpace(runState.CandidateCyclePhase) != "" {
			return true, candidateCycleRecoveryReason(candidateCycleMetadataFromRunState(*runState), "active candidate cycle")
		}
		if meta.WorktreePath != "" && filepath.Clean(runState.WorktreePath) == filepath.Clean(meta.WorktreePath) {
			return true, "matched live run-state"
		}
		if meta.AttemptID != "" && runState.AttemptID == meta.AttemptID {
			return true, "matched live run-state"
		}
	}
	if meta.Liveness != nil {
		if meta.Liveness.PID > 0 && trackerProcessAlive(meta.Liveness.PID) {
			return true, "live pid"
		}
		if !meta.Liveness.ExpiresAt.IsZero() && now.Before(meta.Liveness.ExpiresAt) {
			return true, "unexpired liveness"
		}
		if !meta.Liveness.RefreshedAt.IsZero() && now.Sub(meta.Liveness.RefreshedAt) <= 2*time.Minute {
			return true, "fresh liveness"
		}
	}
	return false, "stale liveness"
}

// ExecutionCleanupManager owns conservative reclamation of DDx temp execution
// resources for one project.
type ExecutionCleanupManager struct {
	ProjectRoot     string
	TempRoot        string
	ScratchRoots    []string
	ScratchPrefixes []string
	ScratchMinAge   time.Duration
	GitOps          GitOps
	DryRun          bool
	Now             func() time.Time
	Probe           ExecutionCleanupLivenessProbe
	// RetainDays controls how many days of evidence dirs under
	// .ddx/executions/ to retain. 0 disables the prune; default is 90.
	RetainDays int
}

// NewExecutionCleanupManager constructs a cleanup manager with the default
// DDx temp worktree root and the default liveness probe.
func NewExecutionCleanupManager(projectRoot string, gitOps GitOps) *ExecutionCleanupManager {
	return &ExecutionCleanupManager{
		ProjectRoot: projectRoot,
		TempRoot:    executionCleanupTempRoot(projectRoot),
		RetainDays:  executionCleanupRetainDays(projectRoot),
		GitOps:      gitOps,
		Now:         time.Now,
		Probe:       defaultExecutionCleanupLivenessProbe{},
	}
}

// executionCleanupRetainDays returns the configured retain_days for evidence
// dirs, defaulting to defaultEvidenceRetainDays when not set in config.
func executionCleanupRetainDays(projectRoot string) int {
	if projectRoot != "" {
		projectConfig := ddxroot.JoinProject(projectRoot, "config.yaml")
		cfg, err := config.LoadFromFile(projectConfig)
		if err == nil && cfg != nil && cfg.Executions != nil {
			return cfg.Executions.ResolveRetainDays()
		}
	}
	return defaultEvidenceRetainDays
}

// Cleanup scans the configured DDx temp worktree root, consults the project
// run-state file and git worktree registry, and conservatively removes stale
// DDx-owned temp resources.
func (m *ExecutionCleanupManager) Cleanup(ctx context.Context) (ExecutionCleanupSummary, error) {
	summary := ExecutionCleanupSummary{
		ProjectRoot: m.ProjectRoot,
		TempRoot:    m.tempRoot(),
	}
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return summary, err
		}
	}
	if summary.TempRoot == "" {
		summary.TempRoot = executionCleanupTempRoot(m.ProjectRoot)
	}
	if summary.TempRoot == "" {
		return summary, errors.New("execution cleanup: temp root is empty")
	}
	if m.ProjectRoot == "" {
		return summary, errors.New("execution cleanup: project root is empty")
	}
	now := time.Now
	if m.Now != nil {
		now = m.Now
	}
	probe := m.Probe
	if probe == nil {
		probe = defaultExecutionCleanupLivenessProbe{}
	}

//go:build !windows

package agent

import (
	"os/exec"
	"syscall"
)

// cmdSetProcessGroup configures cmd so that it and all its children share a
// new process group (Setpgid) and are automatically killed when the parent
// thread dies (Pdeathsig). This ensures that if the parent worker dies
// abnormally (SIGKILL, crash, OOM), the harness child is reaped by the kernel
// rather than orphaning to PID 1.
//
// Pdeathsig is sent when the creating thread dies, not the process, so the
// caller must use runtime.LockOSThread around cmd.Start() to prevent Go
// runtime from migrating the goroutine to a different OS thread. See
// golang.org/issue/27505 for details.
//
// Note: Pdeathsig is Linux-only. macOS and Windows do not support it; the
// graceful shutdown path (cmdKillProcessGroup on context cancellation) serves
// as the fallback for those platforms, and the orphan reaper is the final
// backstop for already-dead workers.
func cmdSetProcessGroup(cmd *exec.Cmd) {
	cmd.SysProcAttr = &syscall.SysProcAttr{
		Setpgid:   true,
		Pdeathsig: syscall.SIGKILL,
	}
}

// cmdKillProcessGroup sends SIGKILL to the entire process group of cmd.
// Because cmd was started with Setpgid=true, its PID equals its PGID, so
// passing -pid kills all descendants that inherited the group.
func cmdKillProcessGroup(cmd *exec.Cmd) {
	if cmd.Process == nil {
		return
	}
	_ = syscall.Kill(-cmd.Process.Pid, syscall.SIGKILL)
}

package cmd

import (
	"context"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

const (
	defaultWorkerDirStaleAge          = 30 * time.Minute
	executionRetentionArchiveRoot     = ".ddx/executions-archive"
	executionRetentionOverrideEnv     = "DDX_EXECUTION_RETAIN_DAYS"
	executionRetentionTimestampLayout = "20060102T150405"
)

type executionRetentionMode int

const (
	executionRetentionDisabled executionRetentionMode = iota
	executionRetentionArchive
	executionRetentionDelete
)

type executionRetentionPolicy struct {
	days int
	mode executionRetentionMode
}

type startupHousekeepingReport struct {
	ProjectRoot string
	TempRoot    string

	StaleWorktrees     int64
	StaleWorkerDirs    int64
	StaleExecutionDirs int64

	RemovedRegisteredWorktrees  int64
	RemovedUnregisteredTempDirs int64
	RemovedWorkerDirs           int64
	ArchivedExecutionDirs       int64
	DeletedExecutionDirs        int64

	Warnings []agent.ExecutionCleanupWarning
}

type startupHousekeepingRunner struct {
	projectRoot     string
	tempRoot        string
	worktreeMaxAge  time.Duration
	workerDirMaxAge time.Duration
	now             func() time.Time
	retentionPolicy executionRetentionPolicy
}

func newStartupHousekeepingRunner(projectRoot string) *startupHousekeepingRunner {
	return &startupHousekeepingRunner{
		projectRoot:     projectRoot,
		tempRoot:        config.ExecutionTempRoot(projectRoot),
		worktreeMaxAge:  worktreeReapMaxAgeFromEnv(),
		workerDirMaxAge: defaultWorkerDirStaleAge,
		retentionPolicy: resolveExecutionRetentionPolicy(projectRoot),
	}
}

func (r *startupHousekeepingRunner) Cleanup(ctx context.Context) (agent.ExecutionCleanupSummary, error) {
	if r == nil {
		return agent.ExecutionCleanupSummary{}, nil
	}
	report, err := r.scan(ctx, true)
	if err != nil {
		return agent.ExecutionCleanupSummary{
			ProjectRoot: r.projectRoot,
			TempRoot:    r.tempRoot,
		}, err
	}
	return agent.ExecutionCleanupSummary{
		ProjectRoot:                 report.ProjectRoot,
		TempRoot:                    report.TempRoot,
		RemovedRegisteredWorktrees:  report.RemovedRegisteredWorktrees,
		RemovedUnregisteredTempDirs: report.RemovedUnregisteredTempDirs,
		RemovedWorkerDirs:           report.RemovedWorkerDirs,
		RemovedEvidenceDirs:         report.ArchivedExecutionDirs + report.DeletedExecutionDirs,
		Warnings:                    append([]agent.ExecutionCleanupWarning(nil), report.Warnings...),
	}, nil
}

func (r *startupHousekeepingRunner) scan(ctx context.Context, apply bool) (startupHousekeepingReport, error) {
	if r == nil {
		return startupHousekeepingReport{}, nil
	}
	report := startupHousekeepingReport{
		ProjectRoot: r.projectRoot,
		TempRoot:    r.tempRoot,
	}
	if r.projectRoot == "" {
		return report, nil
	}
	now := time.Now().UTC()
	if r.now != nil {
		now = r.now()
	}

	runStates, err := agent.ReadRunStates(r.projectRoot)
	if err != nil {
		return report, err
	}
	if err := r.scanWorktrees(ctx, now, runStates, apply, &report); err != nil {
		return report, err
	}
	if err := r.scanWorkerDirs(ctx, now, apply, &report); err != nil {
		return report, err
	}
	if err := r.scanExecutionDirs(ctx, now, runStates, apply, &report); err != nil {
		return report, err
	}
	return report, nil
}

func (r *startupHousekeepingRunner) scanWorktrees(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
	if report.TempRoot == "" {
		return nil
	}
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return err
		}
	}
	entries, err := os.ReadDir(report.TempRoot)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}

	registered := map[string]struct{}{}
	if paths, listErr := (&agent.RealGitOps{}).WorktreeList(r.projectRoot); listErr == nil {
		for _, path := range paths {
			registered[filepath.Clean(path)] = struct{}{}
		}
	}

	for _, entry := range entries {
		if !entry.IsDir() || !strings.HasPrefix(entry.Name(), agent.ExecuteBeadWtPrefix) {
			continue
		}
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}
		info, err := entry.Info()
		if err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    filepath.Join(report.TempRoot, entry.Name()),
				Class:   "worktree_stat",
				Message: err.Error(),
			})
			continue
		}
		if now.Sub(info.ModTime()) < r.worktreeMaxAge {
			continue
		}

		path := filepath.Join(report.TempRoot, entry.Name())
		meta, metaErr := agent.ReadExecutionCleanupMetadata(path)
		if metaErr == nil {
			meta.WorktreePath = firstNonEmpty(meta.WorktreePath, path)
		} else {
			meta = agent.ExecutionCleanupMetadata{WorktreePath: path}
		}
		if worktreeStillLive(meta, runStates, now) {
			continue
		}

		report.StaleWorktrees++
		if !apply {
			continue
		}

		if _, ok := registered[filepath.Clean(path)]; ok {
			if err := (&agent.RealGitOps{}).WorktreeRemove(r.projectRoot, path); err != nil {
				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
					Path:    path,
					Class:   "registered_worktree_remove",
					Message: err.Error(),
				})
				continue
			}
			report.RemovedRegisteredWorktrees++
			continue
		}

		if err := os.RemoveAll(path); err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    path,
				Class:   "unregistered_worktree_remove",
				Message: err.Error(),
			})
			continue
		}
		report.RemovedUnregisteredTempDirs++
	}

	return nil
}

func (r *startupHousekeepingRunner) scanWorkerDirs(ctx context.Context, now time.Time, apply bool, report *startupHousekeepingReport) error {
	root := workerstatus.LivenessDir(r.projectRoot)
	entries, err := os.ReadDir(root)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}

	for _, entry := range entries {
		if !entry.IsDir() || !strings.HasPrefix(entry.Name(), "agent-loop-") {
			continue
		}
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}

		rec, err := workerstatus.ReadLiveness(r.projectRoot, entry.Name())
		if err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    filepath.Join(root, entry.Name(), "status.json"),
				Class:   "worker_dir_read",
				Message: err.Error(),
			})
			continue
		}
		stale, _ := staleWorkerDir(rec, now, r.workerDirMaxAge)
		if !stale {
			continue
		}

		report.StaleWorkerDirs++
		if !apply {
			continue
		}

		dirPath := filepath.Join(root, entry.Name())
		if err := os.RemoveAll(dirPath); err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    dirPath,
				Class:   "worker_dir_remove",
				Message: err.Error(),
			})
			continue
		}
		report.RemovedWorkerDirs++
	}

	return nil
}

func (r *startupHousekeepingRunner) scanExecutionDirs(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
	policy := r.retentionPolicy
	if policy.mode == executionRetentionDisabled {
		return nil
	}

	root := ddxroot.JoinProject(r.projectRoot, "executions")
	entries, err := os.ReadDir(root)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}

	activeAttempts := map[string]struct{}{}
	for _, rs := range runStates {
		if rs.AttemptID != "" {
			activeAttempts[rs.AttemptID] = struct{}{}
		}
	}
	cutoff := now.AddDate(0, 0, -policy.days)

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		if _, ok := activeAttempts[entry.Name()]; ok {
			continue
		}
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}

		dirPath := filepath.Join(root, entry.Name())
		if !hasExecutionEvidenceMarker(dirPath) {
			continue
		}

		info, err := entry.Info()
		if err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    dirPath,
				Class:   "execution_dir_stat",
				Message: err.Error(),
			})
			continue
		}
		if !info.ModTime().Before(cutoff) {
			continue
		}

		report.StaleExecutionDirs++
		if !apply {
			continue
		}

		switch policy.mode {
		case executionRetentionArchive:
			if err := archiveExecutionDir(r.projectRoot, dirPath, entry.Name(), info.ModTime()); err != nil {
				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
					Path:    dirPath,
					Class:   "execution_dir_archive",
					Message: err.Error(),
				})
				continue
			}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"syscall"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

type orphanHarnessProcess struct {
	PID     int
	PPID    int
	Command string
	Cwd     string
}

type orphanHarnessProcessScanner interface {
	Scan(context.Context) ([]orphanHarnessProcess, error)
}

type orphanHarnessLeaseReader interface {
	ClaimLease(id string) (bead.ClaimLeaseRecord, bool, error)
}

type orphanHarnessLeaseReleaser interface {
	Release(id, assignee, targetStatus string) error
}

type orphanHarnessEventAppender interface {
	AppendEvent(id string, event bead.BeadEvent) error
}

// reapOrphanedHarnessChildren kills orphaned harness subprocesses that still
// sit inside this project's execution worktree root and clears the stale lease
// they were holding.
func reapOrphanedHarnessChildren(
	ctx context.Context,
	projectRoot string,
	scanner orphanHarnessProcessScanner,
	leaseReader orphanHarnessLeaseReader,
	releaser orphanHarnessLeaseReleaser,
	appender orphanHarnessEventAppender,
	assignee string,
	log io.Writer,
	emit func(string, map[string]any),
	killGroup func(int) error,
) (int, error) {
	if ctx != nil && ctx.Err() != nil {
		return 0, ctx.Err()
	}
	if scanner == nil || projectRoot == "" {
		return 0, nil
	}
	if killGroup == nil {
		killGroup = func(int) error { return nil }
	}

	processes, err := scanner.Scan(ctx)
	if err != nil {
		return 0, err
	}

	execRoot := canonicalExecRoot(config.ExecutionTempRoot(projectRoot))
	if execRoot == "" {
		return 0, nil
	}

	reaped := 0
	for _, proc := range processes {
		if ctx != nil && ctx.Err() != nil {
			return reaped, ctx.Err()
		}
		if proc.PPID != 1 || proc.PID <= 0 {
			continue
		}
		if !looksLikeHarnessProcess(proc.Command) {
			continue
		}
		beadID, worktree := workerstatus.InferBead(proc.Command, proc.Cwd)
		if beadID == "" || worktree == "" {
			continue
		}
		if !isWithinProjectExecutionRoot(execRoot, worktree) {
			continue
		}
		if leaseReader == nil {
			continue
		}
		lease, found, leaseErr := leaseReader.ClaimLease(beadID)
		if leaseErr != nil || !found || lease.PID <= 0 || processAlive(lease.PID) {
			continue
		}

		diagnosis := fmt.Sprintf(
			"orphaned harness child %d (parent pid 1) in %s; claim owner pid %d is gone",
			proc.PID, worktree, lease.PID,
		)

		if killErr := killGroup(proc.PID); killErr != nil && log != nil {
			_, _ = fmt.Fprintf(log, "startup orphan reaper: failed to kill process group %d for %s: %v\n", proc.PID, beadID, killErr)
		}
		if releaser != nil {
			_ = releaser.Release(beadID, assignee, "")
		}
		if appender != nil {
			body, _ := json.Marshal(map[string]any{
				"reason":             "orphaned_harness_child",
				"bead_id":            beadID,
				"process_pid":        proc.PID,
				"process_parent_pid": proc.PPID,
				"claim_owner_pid":    lease.PID,
				"worktree":           worktree,
				"project_root":       projectRoot,
				"diagnosis":          diagnosis,
			})
			_ = appender.AppendEvent(beadID, bead.BeadEvent{
				Kind:      "operator_attention",
				Summary:   "orphaned_harness_child",
				Body:      string(body),
				Actor:     assignee,
				Source:    "ddx work",
				CreatedAt: time.Now().UTC(),
			})
		}
		if emit != nil {
			emit("loop.operator_attention", map[string]any{
				"reason":             "orphaned_harness_child",
				"bead_id":            beadID,
				"process_pid":        proc.PID,
				"process_parent_pid": proc.PPID,
				"claim_owner_pid":    lease.PID,
				"worktree":           worktree,
				"project_root":       projectRoot,
				"diagnosis":          diagnosis,
			})
		}
		if log != nil {
			_, _ = fmt.Fprintf(log, "startup orphan reaper: reaped orphaned harness child %d for %s\n", proc.PID, beadID)
		}
		reaped++
	}

	return reaped, nil
}

func looksLikeHarnessProcess(cmdline string) bool {
	if strings.TrimSpace(cmdline) == "" {
		return false
	}
	parts := strings.Fields(cmdline)
	if len(parts) == 0 {
		return false
	}
	switch filepath.Base(parts[0]) {
	case "claude", "codex", "gemini", "opencode", "pi":
		return true
	default:
		return false
	}
}

func canonicalExecRoot(path string) string {
	if strings.TrimSpace(path) == "" {
		return ""
	}
	abs, err := filepath.Abs(path)
	if err != nil {
		abs = filepath.Clean(path)
	}
	if real, err := filepath.EvalSymlinks(abs); err == nil {
		abs = real
	}
	return filepath.Clean(abs)
}

func isWithinProjectExecutionRoot(execRoot, worktree string) bool {
	if execRoot == "" || worktree == "" {
		return false
	}
	abs := canonicalExecRoot(worktree)
	if abs == execRoot {
		return true
	}
	prefix := execRoot + string(filepath.Separator)
	return strings.HasPrefix(abs, prefix)
}

func processAlive(pid int) bool {
	if pid <= 0 {
		return false
	}
	proc, err := os.FindProcess(pid)
	if err != nil {
		return false
	}
	return proc.Signal(syscall.Signal(0)) == nil
}

	if projectRoot != "" {
		projectConfig := ddxroot.JoinProject(projectRoot, "config.yaml")
		cfg, err := config.LoadFromFile(projectConfig)
		if err == nil && cfg != nil && cfg.Executions != nil {
			return cfg.Executions.ResolveRetainDays()
		}
	}
	return defaultEvidenceRetainDays
}

// Cleanup scans the configured DDx temp worktree root, consults the project
// run-state file and git worktree registry, and conservatively removes stale
// DDx-owned temp resources.
func (m *ExecutionCleanupManager) Cleanup(ctx context.Context) (ExecutionCleanupSummary, error) {
	summary := ExecutionCleanupSummary{
		ProjectRoot: m.ProjectRoot,
		TempRoot:    m.tempRoot(),
	}
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return summary, err
		}
	}
	if summary.TempRoot == "" {
		summary.TempRoot = executionCleanupTempRoot(m.ProjectRoot)
	}
	if summary.TempRoot == "" {
		return summary, errors.New("execution cleanup: temp root is empty")
	}
	if m.ProjectRoot == "" {
		return summary, errors.New("execution cleanup: project root is empty")
	}
	now := time.Now
	if m.Now != nil {
		now = m.Now
	}
	probe := m.Probe
	if probe == nil {
		probe = defaultExecutionCleanupLivenessProbe{}
	}

	registered := map[string]struct{}{}
	liveRunStates := map[string]struct{}{}
	if m.GitOps != nil {
		paths, err := m.GitOps.WorktreeList(m.ProjectRoot)
		if err != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    m.ProjectRoot,
				Class:   "git_worktree_list",
				Message: err.Error(),
			})
		} else {
			for _, p := range paths {
				registered[filepath.Clean(p)] = struct{}{}
			}
		}
	}
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return summary, err
		}
	}

	runStates, runStateErr := ReadRunStates(m.ProjectRoot)
	if runStateErr != nil {
		summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
			Path:    runStateDirPath(m.ProjectRoot),
			Class:   "run_state_read",
			Message: runStateErr.Error(),
		})
	}
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return summary, err
		}
	}

	entries, err := os.ReadDir(summary.TempRoot)
	if err != nil {
		return summary, fmt.Errorf("execution cleanup: read temp root: %w", err)
	}
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return summary, err
			}
		}
		if !hasAnyPrefix(entry.Name(), executionAttemptDirPrefixes()) {
			continue
		}
		summary.ScannedTempDirs++
		path := filepath.Join(summary.TempRoot, entry.Name())

		meta, metaErr := ReadExecutionCleanupMetadata(path)
		missingMetadata := false
		if metaErr != nil {
			if errors.Is(metaErr, os.ErrNotExist) {
				missingMetadata = true
				meta = ExecutionCleanupMetadata{
					ProjectRoot:  m.ProjectRoot,
					WorktreePath: path,
				}
			} else {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    path,
					Class:   "metadata_read",
					Message: metaErr.Error(),
				})
				continue
			}
		}
		candidateRunStates := runStates
		ownershipMismatch := meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot)
		if ownershipMismatch {
			candidateRunStates = m.runStatesForMetadata(meta, runStates, &summary)
		}

		matchedRunState := matchingRunStateForMeta(candidateRunStates, meta)
		live, reason := probe.IsLive(meta, matchedRunState, now())
		if live {
			if matchedRunState != nil {
				liveRunStates[runStateLiveKey(*matchedRunState)] = struct{}{}
			}
			class := "preserved_temp_dir"
			if isLiveAttemptPreservation(reason) {
				class = "preserved_live_attempt"
			}
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    path,
				Class:   class,
				Message: reason,
			})
			continue
		}
		if ownershipMismatch {
			if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, path) {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    path,
					Class:   "ownership_mismatch",
					Message: fmt.Sprintf("metadata project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
				})
				continue
			}
			if m.isRegisteredWorktree(meta.ProjectRoot, path, &summary) {
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    path,
					Class:   "preserved_foreign_registered_worktree",
					Message: "foreign project worktree is still registered",
				})
				continue
			}
		}

		if _, ok := registered[filepath.Clean(path)]; ok {
			if missingMetadata {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    path,
					Class:   "registered_missing_metadata",
					Message: "registered DDx worktree has no cleanup metadata; preserving",
				})
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    path,
					Class:   "preserved_registered_missing_metadata",
					Message: "registered worktree without cleanup metadata",
				})
				continue
			}
			if m.GitOps == nil {
				summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
					Path:     path,
					Class:    "registered_worktree",
					Message:  "no git ops available to remove registered worktree",
					Blocking: true,
				})
				continue
			}
			reclaimedBytes, reclaimedInodes, measureErr := measureTreeWithContext(ctx, path)
			if measureErr != nil {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    path,
					Class:   "measure_tree",
					Message: measureErr.Error(),
				})
			}
			if !m.DryRun {
				if err := m.GitOps.WorktreeRemove(m.ProjectRoot, path); err != nil {
					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
						Path:     path,
						Class:    "registered_worktree_remove",
						Message:  err.Error(),
						Blocking: true,
					})
					continue
				}
			}
			summary.RemovedRegisteredWorktrees++
			summary.BytesReclaimed += reclaimedBytes
			summary.InodesReclaimed += reclaimedInodes
			class := "removed_registered_worktree"
			if m.DryRun {
				class = "would_remove_registered_worktree"
			}
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    path,
				Class:   class,
				Message: reason,
				Bytes:   reclaimedBytes,
				Inodes:  reclaimedInodes,
			})
			continue
		}

		reclaimedBytes, reclaimedInodes, measureErr := measureTreeWithContext(ctx, path)
		if measureErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    path,
				Class:   "measure_tree",
				Message: measureErr.Error(),
			})
		}
		if !m.DryRun {
			if err := os.RemoveAll(path); err != nil {
				summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
					Path:     path,
					Class:    "unregistered_temp_dir_remove",
					Message:  err.Error(),
					Blocking: false,
				})
				continue
			}
		}
		summary.RemovedUnregisteredTempDirs++
		summary.BytesReclaimed += reclaimedBytes
		summary.InodesReclaimed += reclaimedInodes
		class := "removed_unregistered_temp_dir"
		if m.DryRun {
			class = "would_remove_unregistered_temp_dir"
		}
		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
			Path:    path,
			Class:   class,
			Message: reason,
			Bytes:   reclaimedBytes,
			Inodes:  reclaimedInodes,
		})
	}

	if err := m.cleanupScratchRoots(ctx, &summary, runStates, registered, probe, now()); err != nil {
		return summary, err
	}

	if m.GitOps != nil && summary.RemovedRegisteredWorktrees > 0 && !m.DryRun {
		if err := m.GitOps.WorktreePrune(m.ProjectRoot); err != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    m.ProjectRoot,
				Class:   "worktree_prune",
				Message: err.Error(),
			})
		}
	}

	// Stale run-state files are removed when they point at an execution
	// resource that is no longer live.
	for _, state := range runStates {
		if _, ok := liveRunStates[runStateLiveKey(state)]; ok {
			continue
		}
		if runStateWorktreeStillExists(state) {
			continue
		}
		if removed, bytes := m.removeStaleRunState(state, &summary); removed {
			summary.RemovedRunStateFiles++
			summary.BytesReclaimed += bytes
			summary.InodesReclaimed++
		}
	}

	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return summary, err
		}
	}
	summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ExecuteBeadArtifactDir, "manifest.json", "result.json", &summary)
	m.pruneEvidenceDirs(ctx, &summary, runStates, now())
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return summary, err
		}
	}
	m.pruneAgentLogs(ctx, &summary, runStates, now())
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return summary, err
		}
	}
	m.pruneWorkerDirs(ctx, &summary, now())
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return summary, err
		}
	}
	summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ".ddx/runs", "record.json", "", &summary)
	m.cleanupDurableLandedCandidateRefs(&summary)

	return summary, nil
}

func (m *ExecutionCleanupManager) cleanupScratchRoots(ctx context.Context, summary *ExecutionCleanupSummary, runStates []RunState, registered map[string]struct{}, probe ExecutionCleanupLivenessProbe, now time.Time) error {
	prefixes := m.scratchPrefixes()
	minAge := m.scratchMinAge()
	tempRoot := filepath.Clean(summary.TempRoot)

	for _, root := range m.scratchRoots(summary.TempRoot) {
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}
		entries, err := os.ReadDir(root)
		if err != nil {
			if !os.IsNotExist(err) {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    root,
					Class:   "scratch_root_read",
					Message: err.Error(),
				})
			}
			continue
		}
		for _, entry := range entries {
			if !entry.IsDir() || !hasAnyPrefix(entry.Name(), prefixes) {
				continue
			}
			if ctx != nil {
				if err := ctx.Err(); err != nil {
					return err
				}
			}
			path := filepath.Join(root, entry.Name())
			if sameCleanPath(path, tempRoot) || isPathWithin(path, tempRoot) {
				continue
			}
			summary.ScannedScratchDirs++

			info, err := entry.Info()
			if err != nil {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    path,
					Class:   "scratch_stat",
					Message: err.Error(),
				})
				continue
			}

			meta, metaErr := ReadExecutionCleanupMetadata(path)
			if metaErr != nil {
				if !errors.Is(metaErr, os.ErrNotExist) {
					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
						Path:    path,
						Class:   "scratch_metadata_read",
						Message: metaErr.Error(),
					})
					continue
				}
				meta = ExecutionCleanupMetadata{
					ProjectRoot:  m.ProjectRoot,
					WorktreePath: path,
				}
			}
			if meta.WorktreePath == "" {
				meta.WorktreePath = path
			}

			candidateRunStates := runStates
			if meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot) {
				if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, path) {
					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
						Path:    path,
						Class:   "scratch_ownership_mismatch",
						Message: fmt.Sprintf("metadata project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
					})
					continue
				}
				candidateRunStates = m.runStatesForMetadata(meta, runStates, summary)
				if m.isRegisteredWorktree(meta.ProjectRoot, path, summary) {
					summary.PreservedActiveScratchDirs++
					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
						Path:    path,
						Class:   "preserved_active_scratch_dir",
						Message: "foreign project worktree is still registered",
					})
					continue
				}
			}
			if _, ok := registered[filepath.Clean(path)]; ok {
				summary.PreservedActiveScratchDirs++
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    path,

					Path:    path,
					Class:   "preserved_active_scratch_dir",
					Message: "registered worktree",
				})
				continue
			}

			matchedRunState := matchingRunStateForMeta(candidateRunStates, meta)
			if live, reason := probe.IsLive(meta, matchedRunState, now); live {
				summary.PreservedActiveScratchDirs++
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    path,
					Class:   "preserved_active_scratch_dir",
					Message: reason,
				})
				continue
			}

			if age := now.Sub(info.ModTime()); age < minAge {
				summary.PreservedActiveScratchDirs++
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    path,
					Class:   "preserved_active_scratch_dir",
					Message: fmt.Sprintf("fresh scratch dir age=%s min_age=%s", age.Round(time.Second), minAge),
				})
				continue
			}

			reclaimedBytes, reclaimedInodes, measureErr := measureTreeWithContext(ctx, path)
			if measureErr != nil {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    path,
					Class:   "scratch_measure_tree",
					Message: measureErr.Error(),
				})
			}
			if !m.DryRun {
				if err := os.RemoveAll(path); err != nil {
					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
						Path:     path,
						Class:    "scratch_dir_remove",
						Message:  err.Error(),
						Blocking: false,
					})
					continue
				}
			}
			summary.RemovedScratchDirs++
			summary.ScratchBytesReclaimed += reclaimedBytes
			summary.ScratchInodesReclaimed += reclaimedInodes
			summary.BytesReclaimed += reclaimedBytes
			summary.InodesReclaimed += reclaimedInodes
			class := "removed_scratch_dir"
			if m.DryRun {
				class = "would_remove_scratch_dir"
			}
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    path,
				Class:   class,
				Message: "stale DDx scratch dir",
				Bytes:   reclaimedBytes,
				Inodes:  reclaimedInodes,
			})
		}
	}
	return nil
}

func (m *ExecutionCleanupManager) runStatesForMetadata(meta ExecutionCleanupMetadata, fallback []RunState, summary *ExecutionCleanupSummary) []RunState {
	if meta.ProjectRoot == "" || sameCleanPath(meta.ProjectRoot, m.ProjectRoot) {
		return fallback
	}
	states, err := ReadRunStates(meta.ProjectRoot)
	if err != nil {
		summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
			Path:    runStateDirPath(meta.ProjectRoot),
			Class:   "foreign_run_state_read",
			Message: err.Error(),
		})
		return fallback
	}
	return states
}

func (m *ExecutionCleanupManager) canReclaimForeignTestOwnedPath(projectRoot, path string) bool {
	if projectRoot == "" || !isPathWithin(projectRoot, os.TempDir()) {
		return false
	}
	cleanPath := filepath.Clean(path)
	for _, root := range m.reclaimableTempRoots() {
		if sameCleanPath(cleanPath, root) || isPathWithin(cleanPath, root) {
			return true
		}
	}
	return false
}

func (m *ExecutionCleanupManager) isRegisteredWorktree(projectRoot, path string, summary *ExecutionCleanupSummary) bool {
	if m.GitOps == nil || projectRoot == "" || path == "" {
		return false
	}
	paths, err := m.GitOps.WorktreeList(projectRoot)
	if err != nil {
		summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
			Path:    projectRoot,
			Class:   "foreign_git_worktree_list",
			Message: err.Error(),
		})
		return false
	}
	clean := filepath.Clean(path)
	for _, p := range paths {
		if filepath.Clean(p) == clean {
			return true
		}
	}
	return false
}

func (m *ExecutionCleanupManager) scratchRoots(tempRoot string) []string {
	if len(m.ScratchRoots) > 0 {
		return cleanUniquePaths(m.ScratchRoots)
	}
	var roots []string
	if tempRoot != "" {
		parent := filepath.Dir(filepath.Clean(tempRoot))
		if parent != "" && parent != "." {
			roots = append(roots, parent)
		}
	}
	if m.ProjectRoot != "" {
		roots = append(roots, config.ExecutionScratchRoot(m.ProjectRoot))
	}
	// Always include the legacy process temp dir so changing
	// executions.temp_worktree_root does not strand older DDx-owned scratch.
	roots = append(roots, os.TempDir())
	return cleanUniquePaths(roots)
}

func (m *ExecutionCleanupManager) reclaimableTempRoots() []string {
	tempRoot := m.tempRoot()
	roots := []string{tempRoot}
	roots = append(roots, m.scratchRoots(tempRoot)...)
	roots = append(roots, config.LegacyExecutionTempRoot(), os.TempDir())
	return cleanUniquePaths(roots)
}

func (m *ExecutionCleanupManager) scratchPrefixes() []string {
	if len(m.ScratchPrefixes) > 0 {
		return append([]string(nil), m.ScratchPrefixes...)
	}
	return append([]string(nil), defaultExecutionCleanupScratchPrefixes...)
}

func (m *ExecutionCleanupManager) scratchMinAge() time.Duration {
	if m.ScratchMinAge > 0 {
		return m.ScratchMinAge
	}
	return defaultExecutionCleanupScratchMinAge
}

func cleanUniquePaths(paths []string) []string {
	seen := map[string]struct{}{}
	var out []string
	for _, p := range paths {
		if p == "" {
			continue
		}
		clean := filepath.Clean(p)
		if _, ok := seen[clean]; ok {
			continue
		}
		seen[clean] = struct{}{}
		out = append(out, clean)
	}
	return out
}

func hasAnyPrefix(name string, prefixes []string) bool {
	for _, prefix := range prefixes {
		if prefix != "" && strings.HasPrefix(name, prefix) {
			return true
		}
	}
	return false
}

func sameCleanPath(a, b string) bool {
	if a == "" || b == "" {
		return false
	}
	return filepath.Clean(a) == filepath.Clean(b)
}

func isPathWithin(path, root string) bool {
	if path == "" || root == "" {
		return false
	}
	cleanPath := filepath.Clean(path)
	cleanRoot := filepath.Clean(root)
	if cleanPath == cleanRoot {
		return true
	}
	rel, err := filepath.Rel(cleanRoot, cleanPath)
	if err != nil {
		return false
	}
	return rel != "." && rel != ".." && !strings.HasPrefix(rel, ".."+string(os.PathSeparator))
}

func matchingRunStateForMeta(states []RunState, meta ExecutionCleanupMetadata) *RunState {
	if meta.CandidateRef != "" {
		for i := range states {
			state := states[i]
			if state.CandidateRef != meta.CandidateRef {
				continue
			}
			if meta.CycleIndex != 0 && state.CycleIndex != meta.CycleIndex {
				continue
			}
			return &states[i]
		}
	}
	for i := range states {
		state := states[i]
		if meta.AttemptID != "" && state.AttemptID == meta.AttemptID {
			return &states[i]
		}
		if meta.WorktreePath != "" && state.WorktreePath != "" && filepath.Clean(state.WorktreePath) == filepath.Clean(meta.WorktreePath) {
			return &states[i]
		}
	}
	return nil
}

func isLiveAttemptPreservation(reason string) bool {
	if strings.HasPrefix(reason, "active candidate cycle") || strings.HasPrefix(reason, "candidate ref recovery") {
		return true
	}
	switch reason {
	case "matched live run-state", "unexpired liveness", "fresh liveness", "live pid", "active candidate cycle":
		return true
	default:
		return false
	}
}

func candidateCycleRecoveryReason(meta ExecutionCleanupMetadata, prefix string) string {
	var parts []string
	if meta.CandidateCyclePhase != "" {
		parts = append(parts, "phase="+meta.CandidateCyclePhase)
	}
	if meta.CandidateRef != "" {
		parts = append(parts, "candidate_ref="+meta.CandidateRef)
	}
	if meta.CandidateRev != "" {
		parts = append(parts, "candidate_rev="+meta.CandidateRev)
	}
	if meta.ReviewActive {
		parts = append(parts, "review_active=true")
	}
	if meta.RepairActive {
		parts = append(parts, "repair_active=true")
	}
	if len(parts) == 0 {
		return prefix
	}
	return prefix + " (" + strings.Join(parts, " ") + ")"
}

func candidateCycleMetadataFromRunState(state RunState) ExecutionCleanupMetadata {
	return ExecutionCleanupMetadata{
		BeadID:               state.BeadID,
		AttemptID:            state.AttemptID,
		WorktreePath:         state.WorktreePath,
		ActiveCandidateCycle: strings.TrimSpace(state.CandidateCyclePhase) != "",
		CandidateCyclePhase:  state.CandidateCyclePhase,
		CandidateRef:         state.CandidateRef,
		CandidateRev:         state.CandidateRev,
		CycleIndex:           state.CycleIndex,
		ReviewActive:         state.ReviewActive,
		RepairActive:         state.RepairActive,
	}
}

func runStateLiveKey(state RunState) string {
	if state.AttemptID != "" {
		return "attempt:" + state.AttemptID
	}
	if state.WorktreePath != "" {
		return "path:" + filepath.Clean(state.WorktreePath)
	}
	return "bead:" + state.BeadID
}

func runStateWorktreeStillExists(state RunState) bool {
	if state.WorktreePath == "" {
		return false
	}
	_, err := os.Stat(state.WorktreePath)
	return err == nil
}

func (m *ExecutionCleanupManager) removeStaleRunState(state RunState, summary *ExecutionCleanupSummary) (bool, int64) {
	path := runStatePath(m.ProjectRoot)
	clear := func() error {
		return ClearRunState(m.ProjectRoot)
	}
	if state.AttemptID != "" {
		if attemptPath, err := runStateAttemptPath(m.ProjectRoot, state.AttemptID); err == nil {
			path = attemptPath
			clear = func() error {
				return ClearRunStateAttempt(m.ProjectRoot, state.AttemptID)
			}
		}
	}

	var bytes int64
	present := false
	if info, statErr := os.Stat(path); statErr == nil {
		present = true
		bytes = info.Size()
	} else if os.IsNotExist(statErr) && path != runStatePath(m.ProjectRoot) {
		path = runStatePath(m.ProjectRoot)
		if info, legacyErr := os.Stat(path); legacyErr == nil {
			present = true
			bytes = info.Size()
			clear = func() error {
				return ClearRunState(m.ProjectRoot)
			}
		}
	}
	if !m.DryRun {
		if err := clear(); err != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    path,
				Class:   "run_state_clear",
				Message: err.Error(),
			})
		}
	}
	if !present {
		return false, 0
	}
	class := "removed_run_state"
	if m.DryRun {
		class = "would_remove_run_state"
	}
	summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
		Path:    path,
		Class:   class,
		Message: "stale run-state",
		Bytes:   bytes,
		Inodes:  1,
	})
	return true, bytes
}

func (m *ExecutionCleanupManager) tempRoot() string {
	if m != nil && m.TempRoot != "" {
		return m.TempRoot

// Package workerstatus reports on live "ddx work" / "ddx try" processes,
// scoped to a specific project root by default.
//
// Operators and agents asking "is the worker still working beads?" must be
// able to answer the question for one project at a time. A global process
// scan ("ps aux | grep ddx work") returns workers from every checkout on the
// machine and produces a misleading "yes, working" signal when the worker
// belongs to a different repository. This package filters live workers by
// the resolved project root so the answer always matches the question.
package workerstatus

import (
	"context"
	"path/filepath"
	"regexp"
	"strings"
	"time"
)

// LiveWorker describes one running ddx worker process.
type LiveWorker struct {
	PID                int             `json:"pid"`
	Command            string          `json:"command"`
	StartedAt          time.Time       `json:"started_at"`
	AgeSeconds         float64         `json:"age_seconds"`
	Age                string          `json:"age"`
	ProjectRoot        string          `json:"project_root"`
	BeadID             string          `json:"bead_id,omitempty"`
	AttemptID          string          `json:"attempt_id,omitempty"`
	Phase              string          `json:"phase,omitempty"`
	Message            string          `json:"message,omitempty"`
	ChildPID           int             `json:"child_pid,omitempty"`
	LastActivityAt     time.Time       `json:"last_activity_at,omitempty"`
	ExecutionWorktree  string          `json:"execution_worktree,omitempty"`
	Cwd                string          `json:"cwd,omitempty"`
	ProviderChildren   []ProviderChild `json:"provider_children,omitempty"`
	StaleMonitorShells int             `json:"stale_monitor_shells,omitempty"`
}

// ProviderChild describes a provider CLI subprocess observed under a worker.
//
// RouteOwner is set when the child's provider matches the worker's active
// route/harness; such a child is legitimate route work and is never reaped.
// NonRoute is set on a provider CLI whose provider does not match the active
// route — an unrelated harness the running-phase guard terminates — and
// Diagnostic carries an operator-facing explanation for that quarantine.
type ProviderChild struct {
	PID        int     `json:"pid"`
	Provider   string  `json:"provider"`
	Harness    string  `json:"harness,omitempty"`
	RouteOwner string  `json:"route_owner,omitempty"`
	Phase      string  `json:"phase,omitempty"`
	AgeSeconds float64 `json:"age_seconds"`
	NonRoute   bool    `json:"non_route,omitempty"`
	Diagnostic string  `json:"diagnostic,omitempty"`
}

// Scanner discovers live ddx worker processes on the host.
type Scanner interface {
	Scan(ctx context.Context) ([]LiveWorker, error)
}

// New returns the platform-appropriate Scanner. On Linux this reads /proc.
// On other platforms it returns an empty list; the caller's tests and the
// --all-projects escape hatch remain meaningful regardless.
func New() Scanner {
	return newSystemScanner()
}

// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
// total) embedded in argv strings or worktree paths.
var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)

// executionWorktreePattern matches the conventional execute-bead worktree
// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
// in a path. The directory name is enough to identify the worktree even when
// the surrounding path is unconventional.
var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)

// InferBead extracts a bead ID and execution worktree path from the worker's
// command line and current working directory. It returns the longest worktree
// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
// the inline worker has chdir'd into the isolated worktree), and the first
// bead ID matched in either the command line or the worktree path.
//
// Either return value may be empty when no signal is present, which is the
// expected case for a long-running `ddx work` drain that has not yet started
// a specific bead.
func InferBead(cmdline, cwd string) (beadID, worktree string) {
	worktree = extractWorktreePath(cwd)
	if worktree == "" {
		worktree = extractWorktreePath(cmdline)
	}

	if m := beadIDPattern.FindString(worktree); m != "" {
		beadID = m
	}
	if beadID == "" {
		if m := beadIDPattern.FindString(cmdline); m != "" {
			beadID = m
		}
	}
	if beadID == "" {
		if m := beadIDPattern.FindString(cwd); m != "" {
			beadID = m
		}
	}
	return beadID, worktree
}

func extractWorktreePath(s string) string {
	if s == "" {
		return ""
	}
	if !strings.Contains(s, ".execute-bead-wt-") {
		return ""
	}
	matches := executionWorktreePattern.FindStringIndex(s)
	if matches == nil {
		return ""
	}
	start := matches[0]
	end := matches[1]
	for start > 0 {
		r := s[start-1]
		if r == ' ' || r == '\x00' || r == '\t' {
			break
		}
		start--
	}
	for end < len(s) {
		r := s[end]
		if r == ' ' || r == '\x00' || r == '\t' {
			break
		}
		end++
	}
	return s[start:end]
}

// FilterByProject returns workers whose ProjectRoot resolves to the same path
// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
// filepath.EvalSymlinks so a symlinked checkout matches its real path.
func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
	target := canonicalPath(projectRoot)
	out := make([]LiveWorker, 0, len(workers))
	for _, w := range workers {
		if SamePath(w.ProjectRoot, target) {
			out = append(out, w)
		}
	}
	return out
}

// SamePath reports whether a and b refer to the same on-disk location after
// canonicalisation. It tolerates empty inputs (returning false) so callers
// can safely compare optional fields without prefiltering.
func SamePath(a, b string) bool {
	ca := canonicalPath(a)
	cb := canonicalPath(b)
	if ca == "" || cb == "" {
		return false
	}
	return ca == cb
}

func canonicalPath(p string) string {
	if strings.TrimSpace(p) == "" {
		return ""
	}
	abs, err := filepath.Abs(p)
	if err != nil {
		abs = filepath.Clean(p)
	}
	if resolved, err := filepath.EvalSymlinks(abs); err == nil {
		return resolved
	}
	return abs
}

// FormatAge renders a duration as a short human-readable string mirroring
// the conventions used by the server-backed worker list (`5s`, `12m`,
// `1h30m`). It is intended for terminal output; JSON output uses
// AgeSeconds as the numeric source of truth.
func FormatAge(d time.Duration) string {
	if d < time.Minute {
		if d < 0 {
			d = 0
		}
		return roundedSeconds(d)
	}
	if d < time.Hour {
		return roundedMinutes(d)
	}
	hours := int(d.Hours())
	mins := int(d.Minutes()) % 60
	if mins == 0 {
		return durationHours(hours)
	}
	return durationHoursMinutes(hours, mins)
}

func roundedSeconds(d time.Duration) string {
	secs := int(d.Seconds())
	return durationSeconds(secs)
}

func roundedMinutes(d time.Duration) string {
	mins := int(d.Minutes())
	return durationMinutes(mins)
}

func durationSeconds(n int) string { return formatUnit(n, "s") }
func durationMinutes(n int) string { return formatUnit(n, "m") }
func durationHours(n int) string   { return formatUnit(n, "h") }
func durationHoursMinutes(h, m int) string {
	return formatUnit(h, "h") + formatUnit(m, "m")
}

func formatUnit(n int, unit string) string {
	if n < 0 {
		n = 0
	}
	return itoa(n) + unit
}

func itoa(n int) string {
	if n == 0 {
		return "0"
	}
	neg := n < 0
	if neg {
		n = -n
	}
	var digits [20]byte
	i := len(digits)
	for n > 0 {
		i--
		digits[i] = byte('0' + n%10)
		n /= 10
	}
	out := string(digits[i:])
	if neg {
		return "-" + out
	}
	return out
}

package workerstatus

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
)

// LivenessRecord is the worker-side sidecar written under
// .ddx/workers/<worker-id>/status.json to mirror live progress of a
// long-running ddx work / ddx try attempt without rewriting beads.jsonl.
//
// The bead tracker remains the durable claim marker; this sidecar carries
// the high-frequency liveness signal so operators can answer "is the worker
// alive and what is it doing?" without inflating tracker churn.
type LivenessRecord struct {
	WorkerID           string          `json:"worker_id"`
	ProjectRoot        string          `json:"project_root,omitempty"`
	CurrentBead        string          `json:"current_bead,omitempty"`
	AttemptID          string          `json:"attempt_id,omitempty"`
	Phase              string          `json:"phase,omitempty"`
	Message            string          `json:"message,omitempty"`
	Route              string          `json:"route,omitempty"`
	Harness            string          `json:"harness,omitempty"`
	Model              string          `json:"model,omitempty"`
	Profile            string          `json:"profile,omitempty"`
	PID                int             `json:"pid,omitempty"`
	ChildPID           int             `json:"child_pid,omitempty"`
	ProviderChildren   []ProviderChild `json:"provider_children,omitempty"`
	StaleMonitorShells int             `json:"stale_monitor_shells,omitempty"`
	StartedAt          time.Time       `json:"started_at,omitempty"`
	LastActivityAt     time.Time       `json:"last_activity_at"`
}

// LivenessTTL is the freshness window for treating a worker sidecar as
// "active". Defaults to 3× the bead tracker heartbeat interval (which is
// 30s) so a sidecar that has not been touched in ~90s is treated as stale.
var LivenessTTL = 90 * time.Second

// LivenessDir returns the worker sidecar directory for a project.
func LivenessDir(projectRoot string) string {
	inTree := ddxroot.InTree(projectRoot)
	if info, err := os.Stat(inTree); err == nil && info.IsDir() {
		return filepath.Join(inTree, "workers")
	}
	return ddxroot.JoinProject(projectRoot, "workers")
}

// LivenessPath returns the status.json path for a worker under projectRoot.
func LivenessPath(projectRoot, workerID string) string {
	return filepath.Join(LivenessDir(projectRoot), workerID, "status.json")
}

// WriteLiveness writes rec to .ddx/workers/<workerID>/status.json using a
// tmp-then-rename so concurrent readers never see a half-written file.
func WriteLiveness(projectRoot, workerID string, rec LivenessRecord) error {
	if projectRoot == "" || workerID == "" {
		return fmt.Errorf("workerstatus: project root and worker id required")
	}
	dir := filepath.Join(LivenessDir(projectRoot), workerID)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("workerstatus: mkdir worker dir: %w", err)
	}
	data, err := json.MarshalIndent(rec, "", "  ")
	if err != nil {
		return fmt.Errorf("workerstatus: marshal liveness: %w", err)
	}
	data = append(data, '\n')
	final := filepath.Join(dir, "status.json")
	tmp, err := os.CreateTemp(dir, "status-*.tmp")
	if err != nil {
		return fmt.Errorf("workerstatus: create tmp: %w", err)
	}
	tmpName := tmp.Name()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: write tmp: %w", err)
	}
	if err := tmp.Close(); err != nil {
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: close tmp: %w", err)
	}
	if err := os.Rename(tmpName, final); err != nil {
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: rename: %w", err)
	}
	return nil
}

// ReadLiveness reads the sidecar for workerID under projectRoot.
func ReadLiveness(projectRoot, workerID string) (LivenessRecord, error) {
	var rec LivenessRecord
	data, err := os.ReadFile(LivenessPath(projectRoot, workerID))
	if err != nil {
		return rec, err
	}
	if err := json.Unmarshal(data, &rec); err != nil {
		return rec, fmt.Errorf("workerstatus: parse liveness: %w", err)
	}
	return rec, nil
}

// ListLiveness reads every status.json sidecar under projectRoot's worker
// directory. Malformed sidecars are skipped silently — the sidecar is
// best-effort observability, not authoritative state.
func ListLiveness(projectRoot string) ([]LivenessRecord, error) {
	dir := LivenessDir(projectRoot)
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}
	var out []LivenessRecord
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		rec, err := ReadLiveness(projectRoot, entry.Name())
		if err != nil {
			continue
		}
		out = append(out, rec)
	}
	sort.Slice(out, func(i, j int) bool {
		return out[i].LastActivityAt.After(out[j].LastActivityAt)
	})
	return out, nil
}

// IsFresh reports whether rec.LastActivityAt is within LivenessTTL of now.
func (r LivenessRecord) IsFresh(now time.Time) bool {
	if r.LastActivityAt.IsZero() {
		return false
	}
	return now.Sub(r.LastActivityAt) <= LivenessTTL
}

