	data, err := os.ReadFile(matches[0])
	if err != nil {
		t.Fatalf("read cleanup report: %v", err)
	}
	var report attemptProcessCleanupReport
	if err := json.Unmarshal(data, &report); err != nil {
		t.Fatalf("parse cleanup report: %v", err)
	}
	return report
}

