218	func (r *startupHousekeepingRunner) scanWorkerDirs(ctx context.Context, now time.Time, apply bool, report *startupHousekeepingReport) error {
219		root := workerstatus.LivenessDir(r.projectRoot)
220		entries, err := os.ReadDir(root)
221		if err != nil {
222			if os.IsNotExist(err) {
223				return nil
224			}
225			return err
226		}
227	
228		for _, entry := range entries {
229			if !entry.IsDir() || !strings.HasPrefix(entry.Name(), "agent-loop-") {
230				continue
231			}
232			if ctx != nil {
233				if err := ctx.Err(); err != nil {
234					return err
235				}
236			}
237	
238			rec, err := workerstatus.ReadLiveness(r.projectRoot, entry.Name())
239			if err != nil {
240				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
241					Path:    filepath.Join(root, entry.Name(), "status.json"),
242					Class:   "worker_dir_read",
243					Message: err.Error(),
244				})
245				continue
246			}
247			stale, _ := staleWorkerDir(rec, now, r.workerDirMaxAge)
248			if !stale {
249				continue
250			}
251	
252			report.StaleWorkerDirs++
253			if !apply {
254				continue
255			}
256	
257			dirPath := filepath.Join(root, entry.Name())
258			if err := os.RemoveAll(dirPath); err != nil {
259				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
260					Path:    dirPath,
261					Class:   "worker_dir_remove",
262					Message: err.Error(),
263				})
264				continue
265			}
266			report.RemovedWorkerDirs++
267		}
268	
269		return nil
270	}
